<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Algorithm Visualizer</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 20px;
  }
  h1 { margin-bottom: 16px; font-size: 1.5rem; color: #e94560; }
  .controls { display: flex; gap: 12px; margin-bottom: 16px; }
  button {
    padding: 8px 20px;
    border: none;
    border-radius: 6px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.2s, transform 0.1s;
  }
  button:hover { transform: translateY(-1px); }
  #sort { background: #e94560; color: #fff; }
  #shuffle { background: #0f3460; color: #eee; }
  #reset { background: #16213e; color: #eee; border: 1px solid #333; }
  .info { margin-bottom: 8px; font-size: 0.9rem; color: #aaa; }
  #bars {
    display: flex;
    align-items: flex-end;
    gap: 4px;
    height: 320px;
    width: 100%;
    max-width: 800px;
    overflow-x: auto;
    padding: 10px 0;
  }
  .bar {
    flex: 1;
    min-width: 4px;
    background: #e94560;
    border-radius: 3px 3px 0 0;
    transition: height 0.2s ease, background-color 0.2s ease;
    position: relative;
  }
  .bar.comparing { background: #fca311; }
  .bar.sorted { background: #4cc9f0; }
</style>
</head>
<body>

<h1>Sorting Visualizer</h1>
<div class="controls">
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>
<div class="info" id="status"></div>
<div id="bars"></div>

<script>
(function () {
  const barsEl = document.getElementById('bars');
  const statusEl = document.getElementById('status');
  let arr = [];
  let isSorting = false;

  function render() {
    barsEl.innerHTML = '';
    const maxVal = Math.max(...arr, 1);
    arr.forEach((val, i) => {
      const bar = document.createElement('div');
      bar.className = 'bar';
      const heightPct = (val / maxVal) * 90;
      bar.style.height = Math.round(heightPct) + '%';
      barsEl.appendChild(bar);
    });
  }

  function shuffleArray() {
    arr = [];
    for (let i = 10; i > 0; i--) {
      const v = Math.floor(Math.random() * 90) + 5;
      arr.push(v);
    }
    render();
    statusEl.textContent = 'Array shuffled.';
  }

  function resetAll() {
    arr = [];
    for (let i = 10; i > 0; i--) {
      const v = Math.floor(Math.random() * 90) + 5;
      arr.push(v);
    }
    render();
    statusEl.textContent = 'Array reset.';
  }

  function isSorted() {
    for (let i = 1; i < arr.length; i++) {
      if (arr[i] < arr[i - 1]) return false;
    }
    return true;
  }

  // Bubble sort — one comparison per step
  function bubbleSortStep() {
    if (isSorted()) return true;
    let swapped = false;
    for (let i = 0; i < arr.length - 1; i++) {
      if (arr[i] > arr[i + 1]) {
        [arr[i], arr[i + 1]] = [arr[i + 1], arr[i]];
        swapped = true;
      }
    }
    return !swapped;
  }

  // Expose API on window
  window.viz = {
    array() { return [...arr]; },
    setArray(a) {
      arr = Array.from(a);
      render();
    },
    sortStep() {
      if (isSorting) return false;
      isSorting = true;
      const done = bubbleSortStep();
      statusEl.textContent = done ? 'Sorted!' : '';
      return done;
    },
    sorted() { return isSorted(); }
  };

  document.getElementById('sort').addEventListener('click', () => {
    while (!window.viz.sortStep()) {}
  });

  document.getElementById('shuffle').addEventListener('click', shuffleArray);
  document.getElementById('reset').addEventListener('click', resetAll);

  // Initial state
  arr = [];
  for (let i = 10; i > 0; i--) {
    const v = Math.floor(Math.random() * 90) + 5;
    arr.push(v);
  }
  render();
})();
</script>

</body>
</html>
